start_time":890.24,"speaker_name":"Josh Santo"},{"text":"So there''s not a title screen that says on the job training.","index":295,"end_time":895.52,"speaker_id":0,"start_time":892.48,"speaker_name":"Josh Santo"},{"text":"Oh.","index":296,"end_time":898.01,"speaker_id":1,"start_time":897.61,"speaker_name":"Paula Ocampo"},{"text":"Okay.","index":297,"end_time":900.57,"speaker_id":2,"start_time":900.01,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":298,"end_time":903.09,"speaker_id":2,"start_time":902.73,"speaker_name":"Baylee Gunnell"},{"text":"I wonder if that got.","index":299,"end_time":904.17,"speaker_id":2,"start_time":903.09,"speaker_name":"Baylee Gunnell"},{"text":"I thought we had that before.","index":300,"end_time":906.01,"speaker_id":2,"start_time":904.57,"speaker_name":"Baylee Gunnell"},{"text":"Okay, okay.","index":301,"end_time":907.97,"speaker_id":2,"start_time":906.41,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, we can, we can add that in now.","index":302,"end_time":909.93,"speaker_id":2,"start_time":907.97,"speaker_name":"Baylee Gunnell"},{"text":"That makes sense now so we can get that updated and then.","index":303,"end_time":920.41,"speaker_id":2,"start_time":910.41,"speaker_name":"Baylee Gunnell"},{"text":"Okay, I think that should cover everything here so we can kick this back to our team to work through those revisions then.","index":304,"end_time":931.03,"speaker_id":2,"start_time":921.53,"speaker_name":"Baylee Gunnell"},{"text":"All right.","index":305,"end_time":931.83,"speaker_id":0,"start_time":931.35,"speaker_name":"Josh Santo"},{"text":"Awesome.","index":306,"end_time":934.63,"speaker_id":2,"start_time":934.07,"speaker_name":"Baylee Gunnell"},{"text":"Anything else you wanted to talk about, Josh or Paula?","index":307,"end_time":938.75,"speaker_id":2,"start_time":935.35,"speaker_name":"Baylee Gunnell"},{"text":"Did you have anything else?","index":308,"end_time":939.75,"speaker_id":2,"start_time":938.75,"speaker_name":"Bay